# -*- coding: utf-8 -*-
"""
Importador de produtos extraídos dos PDFs do Supermercado Marialva.
Coloque este arquivo na mesma pasta do app.py e rode:
    python importar_produtos_pdfs_marialva.py
"""

import base64
import csv
import gzip
import json
import os
import re
import shutil
import unicodedata
from datetime import datetime

COLUNAS_PRODUTOS = ["ProdutoID", "Produto", "Marca", "Tamanho", "Categoria", "Unidade", "Ativo", "Observacao"]

DADOS_COMPACTADOS = """"""


def normalizar_texto(texto):
    texto = "" if texto is None else str(texto)
    texto = unicodedata.normalize("NFKD", texto)
    texto = "".join(ch for ch in texto if not unicodedata.combining(ch))
    texto = texto.upper()
    texto = re.sub(r"[^A-Z0-9]+", " ", texto)
    texto = re.sub(r"\s+", " ", texto).strip()
    return texto


def chave_tokens(texto):
    texto = normalizar_texto(texto)
    if not texto:
        return ""
    tokens = texto.split()
    # Remove termos muito genéricos que atrapalham pouco, mas mantém marca/tamanho.
    ignorar = {"DE", "DA", "DO", "DAS", "DOS", "E", "A", "O", "C", "S", "P"}
    tokens = [t for t in tokens if t not in ignorar]
    return " ".join(sorted(set(tokens)))


def carregar_produtos_importar():
    bruto = gzip.decompress(base64.b64decode(DADOS_COMPACTADOS.encode("ascii")))
    return json.loads(bruto.decode("utf-8"))


def ler_csv(caminho, colunas):
    if not os.path.exists(caminho):
        return []

    with open(caminho, "r", encoding="utf-8-sig", newline="") as f:
        leitor = csv.DictReader(f)
        linhas = []
        for linha in leitor:
            linhas.append({col: linha.get(col, "") for col in colunas})
        return linhas


def salvar_csv(caminho, colunas, linhas):
    os.makedirs(os.path.dirname(caminho), exist_ok=True)
    with open(caminho, "w", encoding="utf-8-sig", newline="") as f:
        escritor = csv.DictWriter(f, fieldnames=colunas)
        escritor.writeheader()
        escritor.writerows(linhas)


def proximo_id_produto(produtos_existentes):
    maior = 0
    for p in produtos_existentes:
        pid = str(p.get("ProdutoID", ""))
        m = re.search(r"(\d+)$", pid)
        if m:
            maior = max(maior, int(m.group(1)))
    return maior + 1


def fazer_backup(caminho_produtos):
    if not os.path.exists(caminho_produtos):
        return None

    pasta_backup = "backups"
    os.makedirs(pasta_backup, exist_ok=True)

    agora = datetime.now().strftime("%Y%m%d_%H%M%S")
    destino = os.path.join(pasta_backup, f"produtos_backup_antes_pdf_{agora}.csv")
    shutil.copy2(caminho_produtos, destino)
    return destino


def main():
    pasta_dados = "dados"
    caminho_produtos = os.path.join(pasta_dados, "produtos.csv")

    produtos_existentes = ler_csv(caminho_produtos, COLUNAS_PRODUTOS)
    produtos_importar = carregar_produtos_importar()

    backup = fazer_backup(caminho_produtos)

    chaves_existentes = set()
    for p in produtos_existentes:
        produto = p.get("Produto", "")
        marca = p.get("Marca", "")
        tamanho = p.get("Tamanho", "")
        observacao = p.get("Observacao", "")

        chaves_existentes.add(chave_tokens(produto))
        chaves_existentes.add(chave_tokens(f"{produto} {marca} {tamanho}"))

        # Se algum produto já foi importado antes, a descrição original costuma estar no Produto.
        if "Importado dos PDFs" in str(observacao):
            chaves_existentes.add(chave_tokens(produto))

    novo_numero = proximo_id_produto(produtos_existentes)
    novos = []
    ignorados = 0

    for item in produtos_importar:
        descricao = item.get("Produto", "")
        chave = chave_tokens(descricao)

        if not chave or chave in chaves_existentes:
            ignorados += 1
            continue

        produto_id = f"PROD{novo_numero:03d}"
        novo_numero += 1

        novo = {
            "ProdutoID": produto_id,
            "Produto": descricao,
            "Marca": item.get("Marca", ""),
            "Tamanho": item.get("Tamanho", ""),
            "Categoria": item.get("Categoria", ""),
            "Unidade": item.get("Unidade", "Unidade"),
            "Ativo": item.get("Ativo", "Sim"),
            "Observacao": item.get("Observacao", ""),
        }

        novos.append(novo)
        chaves_existentes.add(chave)

    todos = produtos_existentes + novos
    salvar_csv(caminho_produtos, COLUNAS_PRODUTOS, todos)

    print("Importação dos PDFs concluída com sucesso!")
    print(f"Produtos encontrados nos PDFs: {len(produtos_importar)}")
    print(f"Produtos novos adicionados ao sistema: {len(novos)}")
    print(f"Produtos ignorados por possível duplicidade: {ignorados}")
    print(f"Total atual no cadastro de produtos: {len(todos)}")
    if backup:
        print(f"Backup criado em: {backup}")
    print("Agora atualize o navegador do sistema com F5.")


if __name__ == "__main__":
    main()
